var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"어라? 여기서 못 보던 아줌마네?","JPN":"あれ？　初めて見るおばさんだね？","ENG":"Huh? You're someone I've never seen before.","TWN":"嗯？是我沒見過的阿姨欸？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"아줌마는 누구야?","JPN":"おばさん誰？","ENG":"Who's this old lady?","TWN":"阿姨你是誰啊？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……아줌마?","JPN":"……おばさん？","ENG":"...What did you call me?","TWN":"……阿姨？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"야! 이래 봬도 졸업한 뒤에 곧바로 채용시험에서 합격한 거거든?","JPN":"おい、こう見えてもアタシは卒業後すぐに採用試験に合格してるんだぞ！","ENG":"Hey! I got a job as soon as I graduated!","TWN":"喂！我也才畢業工作沒多久欸。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"많아 봤자, 너랑 서너 살 차이밖에 안 난다고!","JPN":"おまえと3、4歳しか変わらないんだからな！","ENG":"Even if I'm old, you and I are only three or four years apart!","TWN":"我頂多只比你大三、四歲而已！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"호오, 그래?","JPN":"へえ、そう？","ENG":"Oh, really?","TWN":"喔，是嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"아줌마 생각보다 어렸구나? 몰랐어!","JPN":"おばさんって思ったより若いんだね！　知らなかった！","ENG":"Guess you're younger than you look! Sorry! My bad!","TWN":"阿姨這麼年輕嗎？我之前不知道！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……너 지금 일부러 그러는 거지?","JPN":"……おまえ、それわざと言ってるんだろう。","ENG":"...You're doing that on purpose, aren't you?!","TWN":"……你是故意的吧？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러는 넌 누구야? 너야말로 여기서 못 보던 녀석인데?","JPN":"そういうおまえこそ誰だ？　初めて見る顔なんだが。","ENG":"Who are you? I've never seen you around here.","TWN":"你又是誰？我怎麼沒在這裡見過你？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"어라? 관리국 시설에 있으면서 나를 모른단 말이야?","JPN":"え？　管理局の施設にいながら私のことを知らないの？","ENG":"Huh? You work in an Administration facility and don't know who I am?","TWN":"喔？你在管理局竟然不認識我？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내가 널 꼭 알아야 하는 거야?","JPN":"おまえが誰だか知る必要があるのか？","ENG":"Do I have to know?","TWN":"我需要認識你嗎！？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"후후! 기대하시라!","JPN":"ふふ！　よーく聞きなさい！","ENG":"Haha! Behold!","TWN":"哼哼！那你就要給我聽好了！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"난 말이지! 관리국으로부터 최연소 전대장 제안까지 받았던 몸이라구!","JPN":"私はね、最年少にして管理局から戦隊長の提案を受けた者！","ENG":"I am the youngest person the Administration offered to become a division Commander!","TWN":"我就是……！管理局選的最年輕戰隊長！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L19_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"물론, 스승님과의 소중한 추억을 간직하기 위해 펜릴 전대에 남기로 했지만.","JPN":"もちろん、師匠との大切な思い出を守りたくてフェンリル戦隊に残ることにしたけどね。","ENG":"But of course, I decided to stay in the Fenrir Division to cherish the memories I have with Master.","TWN":"不過嘛，為了保留與師父珍貴的回憶，還是決定留在了芬里爾戰隊！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 놈의 전대장, 전대장! 지긋지긋하네!","JPN":"また戦隊長かよ、うんざりするなもう！","ENG":"Ugh, \\"Commander.\\" I hate that word!","TWN":"噢……戰隊長，戰隊長！我受夠這個詞了！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게 그렇게나 대단한 거야?","JPN":"その戦隊長ってやつがそんなにすごいもんなのか？","ENG":"Is that really that big of a deal?","TWN":"戰隊長真的很了不起嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"어라, 아줌마 몰랐어?","JPN":"ええ？　おばさん知らないの？","ENG":"Oh, you don't know?","TWN":"嗯，阿姨你不知道嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"관리국으로부터 전대장 제안을 받는 다는 건…….","JPN":"管理局から戦隊長になるよう提案されるってことは……","ENG":"Being offered a Commander position by the Administration means–","TWN":"收到管理局的提案就等於……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BISHOP_REPLACER_NULL_QM","text":{"KOREA":"수연아! 이수연!","JPN":"……キズナ！　カナミ・キズナ！","ENG":"Sooyeon! Lee Sooyeon!","TWN":"秀妍！李秀妍！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"수연아, 여긴 다른 전대가 주둔하고 있는 곳이니까 예의를 지켜야 한다고 했잖아.","JPN":"キズナ、ここは他の戦隊の駐屯地だから言動には気をつけるようにと言っただろう。","ENG":"Sooyeon, I told you to behave yourself because another division is stationed here.","TWN":"秀妍……我都告訴過你了，在其他戰隊的駐地要有禮貌……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"뭐야, 멀대! 아직 나 아무 짓도 안 했거든?","JPN":"何だよ、ヒョロガリ！　私まだ何もしてないし。","ENG":"What, Beanstalk?! I didn't do anything yet!","TWN":"傻大個！我還什麼都沒做呢？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"하하, 안녕하세요? 야크샤 전대원 분이시죠?","JPN":"はは、すみません。ヤクシャー戦隊の方ですよね。","ENG":"Haha, hello. You're the Yaksha Division, right?","TWN":"哈哈，你好？你是夜叉戰隊的人吧？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어? 어어…….","JPN":"え？　あ、うん……","ENG":"Huh? Yeah...?","TWN":"呃？呃呃……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"우리 수연이가 혹시 무슨 실례를 저지르지 않았나요?","JPN":"キズナが何か失礼なことを言いませんでしたか？","ENG":"Was our Sooyeon being rude to you?","TWN":"我們家秀妍沒有冒犯到你吧？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"아니, 보아하니 벌써 저지른 것 같네요.","JPN":"いや……その様子だと、もう言ってしまったようですね。","ENG":"Well, from the looks of it, she already did something.","TWN":"呃，看樣子是已經冒犯了呢。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"수연이 때문에 기분이 상하셨다면, 제가 대신 사과드리겠습니다.","JPN":"キズナのせいで気分を害してしまったのでしたら、変わりにお詫びします。","ENG":"If you were offended by her, I apologize on her behalf.","TWN":"如果秀妍有什麼讓你感到不愉快的話，請允許我代她向你道歉。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……아, 아니야. 별일 없었어.","JPN":"……い、いや。別に。","ENG":"...N-no need. Nothing happened.","TWN":"……不、不用。沒什麼。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"그럼 다행이네요.","JPN":"それならよかったです。","ENG":"I'm glad to hear that.","TWN":"那真是太好了。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"아, 저는 펜릴 전대의 나유빈이라고 합니다. 저 애는 이수연이고요.","JPN":"あ、僕はフェンリル戦隊のイチノセ・カオルで、この子はカナミ・キズナと申します。","ENG":"Oh, by the way, I'm Na Yubin of the Fenrir Division. And this is Lee Sooyeon.","TWN":"啊，我叫羅瑜斌，來自芬里爾戰隊。這位是李秀妍。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"혹시 수연이가 실수했더라도, 그리 마음에 담아두지 않으셨으면 좋겠네요.","JPN":"キズナが何か失礼なことを言っても、あまり気に留めないでくださいね。","ENG":"If she caused you any trouble, please don't take it to heart.","TWN":"如果秀妍犯了錯，希望你不要放在心上。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"야, 멀대! 왜 멋대로 사과하는 거야!! 나 아무 짓도 안 했다고!!","JPN":"ちょっと、ヒョロガリ！　何勝手に謝ってるんだよ！！　私なにもしてないってば！！","ENG":"Hey, Beanstalk! What are you apologizing for?! I said I didn't do anything!!","TWN":"喂，傻大個！你為什麼要道歉！！我說了我還什麼都沒做呢！！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"해바라기씨 초콜렛을 사러 왔을 뿐이야! 여기 아포칼립스에서 밖에 안 판단 말이야!","JPN":"ヒマワリの種チョコレートを買いに来ただけだし！　ここのアポカリプスでしか売ってないんだよ！","ENG":"I was just here to buy some chocolate-covered sunflower seeds! They only sell them here at this Apocalypse Convenience Store!","TWN":"我只是來便利店買葵花籽巧克力的！那東西只有這裡才有！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"YUBIN_YAKSHA_NPC_NULL","text":{"KOREA":"알았으니까 빨리 가자. 스승님이 부르셔.","JPN":"わかったから早く行こう。師匠が呼んでる。","ENG":"Okay, but let's go. Master's calling.","TWN":"知道了，快走吧。師父有事在找你。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUBIN_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SUYEON_YAKSHA_NPC_NULL","text":{"KOREA":"어라? 스승님이 부르신다고?","JPN":"え？　師匠が？","ENG":"Huh? Master wants to see me?","TWN":"嗯？師父有事找我？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……뭐야, 저 녀석들?","JPN":"……何だよあいつら。","ENG":"...Who are those two?","TWN":"……那些人，怎麼回事？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"펜릴 전대라고 했나? 저런 어린 애들까지 동원해서 침식체랑 싸운다고?","JPN":"フェンリル戦隊って言ってたよな。あんな子どもたちまで動員して侵食体と戦わせているのか？","ENG":"The Fenrir Division? So even kids like them are fighting C.O.s?","TWN":"芬里爾戰隊？連那麼小的孩子都要和侵蝕體戰鬥嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국이라는 곳은 대체 뭐하는 곳이야?","JPN":"管理局っていったいどういうとこだよ。","ENG":"What exactly does the Administration even do?","TWN":"管理局到底是個什麼地方？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"얼마 뒤","JPN":"しばらくして","ENG":"A few days later","TWN":"不久後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어머, 일찍 왔구나?","JPN":"あら、早く来たね。","ENG":"Oh. You're up early.","TWN":"哎呀，你來得蠻早啊？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"벌써부터 이렇게 의욕 있는 모습을 보여주다니, 기특한데?","JPN":"もうこんなにやる気満々になってくれるなんて、偉いじゃない。","ENG":"Showing so much enthusiasm already? How admirable.","TWN":"能表現出這樣的動力，真是難得？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"착각하지 마. 난 지각하는 걸 싫어할 뿐이니까.","JPN":"勘違いするな。アタシは遅刻が嫌いなだけだ。","ENG":"Don't get me wrong. I just don't like being late.","TWN":"別誤會了。我只是單純討厭遲到。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그보다 오늘부터 CRF를 다루는 법을 알려준다고 했지?","JPN":"今日からCRFの扱い方を教えてくれるんだろう？","ENG":"You said you would show me how to control CRF starting today, remember?","TWN":"你說過今天開始要教我怎麼使用CRF的吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 그렇게 조바심 낼 필요는 없어.","JPN":"ふふ、そんなに焦らなくていいよ。","ENG":"Fu fuu, there's no need to get antsy.","TWN":"呵呵，不要這麼著急。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"말했잖아. CRF의 활용에 대해 알려줄 사람은 내가 아니라고.","JPN":"言ったでしょう？　CRFのことを教えるのは私じゃないの。","ENG":"I already told you. I'm not the one who's going to teach you about utilizing CRF.","TWN":"我說過了。給你示範CRF的師父不是我。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"도착하기 전까지 시간이 남았으니까, 그전에 잠깐 몇 가지 짚고 넘어가 볼까?","JPN":"到着するまでまだ余裕があるから、その間いくつかおさらいでもしてみようか。","ENG":"We still have time before she arrives, so how about we go over a few things, in the meantime?","TWN":"離她到這裡還有一段時間，在此之前，我們可以簡單聊聊嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이론이라고?","JPN":"理論の話か？","ENG":"Like theory?","TWN":"聊什麼？理論嗎……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 먼저 카운터라는 게 뭐라고 생각해?","JPN":"始めに、カウンターって何だと思う？","ENG":"So, what do you think a Counter is?","TWN":"首先，你是怎麼看待制裁者的呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"네가 말했었잖아. 워치를 손에 넣어서, 초능력을 얻게 된 능력자라고.","JPN":"お前が言ったろう。ウォッチを手に入れて超能力を覚醒した者を指すって。","ENG":"You said it yourself. Counters are people who obtain a Watch and gain superpowers.","TWN":"這個你不是說過嗎？制裁者就是通過能量環獲得超能力的人。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래, 그렇게 말할 줄 알았어. 그리고 또?","JPN":"そう言うと思った。それと？","ENG":"Yes, I knew you'd say that. Anything else?","TWN":"嗯，我就知道你會這麼說。然後呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"카운터 능력이라는 건, 기본적으로 CRF. 현실개변력을 다룰 수 있어야 한다고도 했어.","JPN":"カウンター能力ってのは、基本的にCRF、現実改変力を扱う必要があると言ってたな。","ENG":"I know that Counters need to control the Counter Reality Force, CRF, to use their abilities.","TWN":"說起制裁者能力，基本的就是CRF。有了它才能控制能力。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"애초에 그 방법을 알려주겠다고 오늘 부른 거잖아.","JPN":"その方法を教えるからって、今日アタシをここに呼んだんだろ。","ENG":"And you asked me to come here today, so I can learn about it.","TWN":"你今天叫我來，就是為了告訴我方法吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"역시 잘 알고 있네. 복습이 철저한 걸?","JPN":"ちゃんと理解してるね。復習頑張ってくれたんだ？","ENG":"You know well. Guess you did your homework, hmm?","TWN":"你果然很清楚。複習準備很充分嘛？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 여기서 퀴즈!","JPN":"じゃあ、ここでクイズ！","ENG":"Okay! Pop quiz!","TWN":"那麼……開始提問！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"FX_CUTSCEN_BEEP2"},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그렇다면 카운터가 아닌 평범한 사람은 CRF를 쓸 수 없는 걸까?","JPN":"それなら、カウンターじゃない普通の人間にはCRFを扱えないのでしょうか？","ENG":"Are non-Counters not able to use CRF?","TWN":"除了制裁者以外，普通人可以使用CRF嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"무슨 헛소리야? CRF를 다룰 수 있어야 카운터 능력을 쓸 수 있다면서?","JPN":"何言ってるんだ。CRFを扱えないとカウンター能力が使えないんだろ？","ENG":"What are you talking about? You need to know how to control CRF to use Counter abilities.","TWN":"你在說些什麼啊？不是說能夠掌握CRF才能使用制裁者能力嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"평범한 사람이 초능력 같은 걸 쓸 수 있을 리 없잖아.","JPN":"普通の人間に超能力なんて使えるわけないだろう。","ENG":"So there's no way an ordinary person is able to use superpowers.","TWN":"普通人怎麼可能使用超能力這種東西？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"땡─! 틀렸습니다!","JPN":"ぶぶ～！　ハズレ！","ENG":"BZZZT! Wrong answer!","TWN":"錯……！完全不對！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"FX_CUTSCEN_BEEP2"},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"엥? 뭐라고?","JPN":"え？　どうして？","ENG":"Huh? What?","TWN":"欸？什麼啊？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"CRF는 현실개변력. 말 그대로 <color=#ffd34c>현실을 바꾸는 힘</color>이거든.","JPN":"CRFは現実改変力。すなわち<color=#ffd34c>現実を変える力</color>なの。","ENG":"CRF stands for Counter Reality Force. It means the <color=#ffd34c>power to change reality</color>.","TWN":"CRF是<color=#ffd34c>改變現實的力量</color>。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"인간을 포함한 모든 가능성을 지닌 존재는 CRF를 갖고 있다고 할 수 있어.","JPN":"人間を含め、可能性を秘めたすべての存在はCRFを持っていると言えるよ。","ENG":"So you can say that any being who possesses possibilities, including humans, has CRF.","TWN":"可以說所有具有可能性的存在，包括人類，都擁有CRF。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럼 보통 사람들도 능력을 사용할 수 있다는 뜻이야?","JPN":"じゃあ、普通の人間でも能力が使えるってことか？","ENG":"Then are you telling me that ordinary people can also have superpowers?","TWN":"所以你的意思是普通人也可以使用超能力嘍？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그건 아니야.","JPN":"それはまた違う。","ENG":"No, that's not it.","TWN":"不是。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"왜냐하면 평범한 사람들은 평생에 걸쳐, 자신의 CRF를 조금씩 길게 소모하거든.","JPN":"普通の人間は一生をかけて、自分のCRFを少しずつ、長い間消耗するの。","ENG":"That's because ordinary people spend their CRF in increments over their lifetime.","TWN":"因為普通人會在一生中一點一點地消耗他們的CRF。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"스스로의 의지로, 미약하지만 꾸준하게 주위 현실을 개변하지.","JPN":"自分の意思で、微弱ながらも絶えず周りの現実を改変していくと言えるね。","ENG":"They steadily change their reality little by little through their own will.","TWN":"他們以自己的意志，微小卻持續地改變著周圍的現實。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"예를 들면, 너도 마찬가지야. 앨리스 브레이드우드.","JPN":"たとえば、あなたもそうよ。アリス・ブレイドウッド。","ENG":"For instance, like you, Alice Braidwood.","TWN":"比如說你也是。艾莉絲·布雷德伍德。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"어렸을 때 화재를 겪은 뒤, 줄곧 소방관을 꿈 꿔왔지?","JPN":"子どもの頃火災を経験して、消防士になる夢を持つようになったんでしょう？","ENG":"After that fire incident you had when you were little, you've always dreamt of being a firefighter, right?","TWN":"你小時候因為經歷了火災，就一直夢想成為一名消防員吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 그 꿈을 이루기 위해, 지금껏 꾸준히 노력해서 결국 소방관이 되었잖아?","JPN":"その夢を叶えるために努力し続けた結果、消防士になれたのよね。","ENG":"And you worked hard to achieve that dream, eventually becoming one, didn't you?","TWN":"為了實現這個夢想，你非常努力，最終得願以償，對嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"다시 말해, 조금씩 CRF를 소모한 결과로써 외부의 현실을 개변했다고 할 수 있지.","JPN":"だから、少しずつCRFを消耗したことで外部の現実を改変させたってことになるね。","ENG":"In other words, as a result of consuming CRF in tiny portions, your external reality had changed.","TWN":"換句話說，這就是一點一點消耗CRF而改變外部現實的結果。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……제길, 그런 건 또 어떻게 알아낸 거야?","JPN":"……くそ、なんでそんなことまで知ってるんだ？","ENG":"...Damn, how did you find out about that?","TWN":"……不是，你怎麼知道我以前的事？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"반면에 카운터는 워치를 매개로 자신의 CRF를 단번에 폭발적으로 사용할 수 있어.","JPN":"その反面、カウンターはウォッチを媒介にして自分のCRFを一気にたくさん使うことができるの。","ENG":"On the other hand, Counters can use their Watch as a catalyst to use bursts of their CRF at a time.","TWN":"另一方面，制裁者可以透過能量環一下子爆發性地使用他們的CRF。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"내 능력을 예시로 들면, 이렇게……!","JPN":"私の能力で例えると、こう……！","ENG":"If I use myself as an example, like this...!","TWN":"以我的能力為例，像這樣……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이미지를 상상하는 것으로, 대기 중 수분을 빙결시켜 얼음 당근을 만드는 것도 가능하지.","JPN":"イメージするだけで、大気中の水分を氷結させ、氷のニンジンが作れる。","ENG":"Just by imagining an image, I can create an ice carrot by freezing the moisture in the air.","TWN":"想像一下，通過凍結空氣中的水分也可以製作冰紅蘿蔔。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"잠깐……?","JPN":"待て……","ENG":"Hold on...","TWN":"等等……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그 말은 CRF만 다룰 수 있다면, 카운터는 상상하는 건 무엇이든 이룰 수 있다는 거야?","JPN":"ってことは、CRFさえ扱えればカウンターは想像し得ることなら何でも叶えられるってことか？","ENG":"Then, if Counters learn how to use CRF, they can make anything out of their imagination?","TWN":"這是不是表示只要掌控了CRF，制裁者就能實現他們能想像的任何事情？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이론적으로는 그래.","JPN":"理論的にはそうなるね。","ENG":"In theory, yes.","TWN":"理論上是這樣。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 개인의 CRF에는 총량이 존재할뿐더러…….","JPN":"でも個人のCRFには総量が限られていて……","ENG":"But everyone has a different capacity for CRF...","TWN":"但是，一個人的CRF不僅存在總量……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"인간의 사고방식이라는 건, 상상 이상으로 편협하거든.","JPN":"人間の考えられる範疇ってのは意外と狭いものよ。","ENG":"and the human mind is narrower than you think.","TWN":"人的思維方式，也比想像的要狹隘。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아무리 카운터라도 상식과 고정관념, 그리고 경험으로부터 자유로울 수는 없으니까.","JPN":"いくらカウンターでも常識と固定観念、自分の経験を越えることを想像するのは難しいの。","ENG":"Because even if you're a Counter, you can't be free from common sense, stereotypes, and experience.","TWN":"就算你是制裁者，你也無法擺脫常識、刻板印象和過往經驗。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"즉, 현실개변력이라는 건…… <color=#ffd34c>유능</color>하지만, <color=#ffd34c>전능</color>한 건 아니야.","JPN":"つまり、現実改変力というのは……<color=#ffd34c>有能</color>だけど<color=#ffd34c>全能</color>な力ではないってこと。","ENG":"So, Counter Reality Force is... <color=#ffd34c>potent</color>, but it's not <color=#ffd34c>omnipotent</color>.","TWN":"換句話說，CRF是……<color=#ffd34c>強大的</color>，但並非<color=#ffd34c>無所不能</color>。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"생각해보면, 귀와 꼬리가 생겨난 것 말고는 뭔가 엄청 큰 변화가 있는 건 아니었어.","JPN":"今思うと、耳と尻尾が生えた以外、なにか大きな変化があったわけじゃない。","ENG":"The more I think about it, nothing drastically changed other than my getting cat ears and tail.","TWN":"仔細一想，除了長出了耳朵和尾巴之外，看起來也沒給我帶來太大的變化。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"급박한 순간이 아니라면, 큰 힘을 발휘할 수 없었고.","JPN":"切迫した瞬間じゃないと、大した能力も発揮できなかった。","ENG":"And unless it was something urgent, I couldn't exert much power.","TWN":"除非是緊要關頭，否則也沒法發揮出多大的力量。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"네 말대로라면…… 그게 내 사고방식이 편협해서 그렇다는 거야?","JPN":"おまえの話の通りなら……それはアタシの思考の幅が狭いせい……ってことか？","ENG":"So according to you... this is all because I'm narrow-minded?","TWN":"照你這麼說……是我的思考方式太狹隘了？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 그게 딱히 네 잘못은 아닌 걸?","JPN":"ふふ、でも別にあなたが悪い訳じゃないよ？","ENG":"Fu fuu, but that's not your fault.","TWN":"呵呵，這難道不是你的錯嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국에서는 사회 혼란을 막기 위해, 카운터의 존재를 적극적으로 은폐하고 있거든.","JPN":"管理局では社会の混乱を防ぐために、カウンターの存在を積極的に隠ぺいしているの。","ENG":"In order to prevent mass panic, the Administration has been actively covering up the existence of Counters.","TWN":"為了防止社會混亂，管理局正在主動隱瞞制裁者的存在。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"현시대에서는 자기가 카운터라는 걸 자각하지 못한 채, 일반인처럼 살아가는 사람들도 많아.","JPN":"今の時代、自分がカウンターということにも気づけず一般人として生きていく人も多いよ。","ENG":"In today's era, there are people who live ordinary lives without realizing they're Counters.","TWN":"當今時代，有很多人過著普通人的生活，並沒有意識到自己是制裁者。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"물론, 아무리 CRF를 다룰 줄 모른다고 해도…….","JPN":"もちろん、CRFの扱い方がわからなくても……","ENG":"Of course, even if they don't know how to control their CRF...","TWN":"當然，就算再不知道如何使用CRF……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"결국, 카운터니까 어느 순간 자기 분야에서 특출한 재능을 보여줄 거야.","JPN":"カウンターであることは事実だから、ある瞬間自分の専門分野で優れた才能を発揮するでしょうね。","ENG":"they'll still show exceptional talent in their respective fields since they are still technically Counters.","TWN":"制裁者畢竟是制裁者，到了某個時候，就會在自己的領域展現出非凡的天賦。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"천재는 단명한다는 말도 있잖아? 어쩌면 그런 사람 중에서 카운터가 있었을지도 모르지.","JPN":"天才は早死にするって、よく言うじゃない？　もしかするとそういう天才の中にカウンターがいたかもしれないね。","ENG":"You know how they say geniuses are short-lived, right? Perhaps among them, some were Counters.","TWN":"有句話說天才是短命的，對吧？也許那些人當中就有制裁者。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……그래서?","JPN":"……で？","ENG":"...So?","TWN":"所以……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럼, 어떻게 해야 카운터로서 CRF를 다룰 수 있는 건데?","JPN":"じゃあアタシはどうすれば、カウンターとしてCRFを扱うことができる？","ENG":"Then what do I have to do to get a grasp on CRF?","TWN":"說了這麼多，我要怎麼控制CRF呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"설마 이미지 트레이닝이나, 쉐도우 복싱 같은 걸 하라는 뜻은 아니겠지?","JPN":"まさか、イメトレとかシャドーボクシングで鍛える……とは言わないだろうな。","ENG":"You're not going to tell me to do image training or shadow-boxing, are you?","TWN":"難道要做想像訓練？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그런 것도 도움이 안 되는 건 아니지만, 우선 스스로의 의식을 개변하는 거야.","JPN":"それも役に立つけど、まずは自分自身の意識を改変することが大事よ。","ENG":"Those do help a little, but what comes first is to change your own consciousness.","TWN":"那也不是不行，但你最緊要的是改變自己的意識。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"의식을 개변한다고?","JPN":"意識を改変する？","ENG":"Change my consciousness?","TWN":"改變意識？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"카운터라는 걸 단순히 <color=#ffd34c>초능력자</color>정도로 받아들이는 게 아니라.","JPN":"カウンターというものを単なる<color=#ffd34c>超能力者</color>だと思わないで。","ENG":"You shouldn't just simply accept the fact that Counters have <color=#ffd34c>superpowers</color>.","TWN":"制裁者並不單純是<color=#ffd34c>超能力者</color>。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"강력한 카운터와 직접 직면해서, 그 힘과 위력을 가까이서 경험하는 것.","JPN":"強力なカウンターと対面して、その力と威力を身近で経験する。","ENG":"Instead, you should directly meet with a powerful Counter, and experience their power up close.","TWN":"直接面對強大的制裁者，近距離感受他們的能力。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이론적으로는 그런 과정을 통해서 스스로의 의식에 영향을 받을 수 있다고 하거든.","JPN":"理論的には、そういう過程で自分の意識を変えることができると言われているよ。","ENG":"Theoretically, such processes have an effect on one's consciousness.","TWN":"理論上來說，透過這樣的過程，可以影響自己的意識。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 어디까지나 이론적인 이야기지만.","JPN":"まあ、これはあくまで理論的な話ね。","ENG":"But it's only theoretical.","TWN":"嗯，這只是理論上的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"카운터와 직면해? 그렇게 말하는 너도 카운터잖아?","JPN":"カウンターと対面する？　そういうおまえもカウンターだろ？","ENG":"Meet with a Counter? But aren't you a Counter?","TWN":"直面制裁者？要這麼說的話，你也是制裁者吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 높게 평가해주니까 고마운데?","JPN":"ふふ、そう評価してくれて嬉しいよ。","ENG":"Fu fuu, I'm flattered you think so highly of me.","TWN":"呵呵，謝謝你對我這麼高的評價。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아쉽게도 내 능력은 조금 특이한 편이라서, 다짜고짜 위력을 보여주기에는 적합하지 않아.","JPN":"残念ながら私の能力はちょっと変わった能力でね、突然威力を見せるのは難しいの。","ENG":"But unfortunately, my abilities are a bit unusual, so it's hard for me to show you what a Counter can really do.","TWN":"但很遺憾，我的能力有些不同尋常，不適合直接向你展示。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서 오늘은 특별히 <color=#ffd34c>관리국의 에이스</color>님을 불렀지.","JPN":"だから今日は特別に<color=#ffd34c>管理局のエース</color>を招待したよ。","ENG":"That's why I personally asked <color=#ffd34c>the ace of the Administration</color> to come in today.","TWN":"所以，我今天特別邀請了一位<color=#ffd34c>管理局的王牌</color>。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국의 에이스라고……?","JPN":"管理局のエース……？","ENG":"The ace of the Administration...?","TWN":"管理局的王牌……？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아, 마침 도착한 모양이네.","JPN":"あ、ちょうど着いたみたいね。","ENG":"Oh, I think she's here.","TWN":"啊，看來來得正是時候。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"앗!? 그때 소방관 아줌마잖아?","JPN":"あっ！？　あの時の消防士おばさんじゃん！","ENG":"Huh?! It's that firefighter lady!","TWN":"喔？！你是那個時候的消防員阿姨吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……그때 그 왈가닥?","JPN":"……あの時のお転婆娘？","ENG":"…That tomboy?","TWN":"……那個時候的瘋丫頭？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};